     1→mod config;
     2→mod db;
     3→mod email;
     4→mod http;
     5→
     6→use std::path::{Path, PathBuf};
     7→use std::time::Duration;
     8→
     9→use config::load_config;
    10→use db::{
    11→    cmd_dump, is_seen, last_seen_num, migrate_history_file, open_db, record_download_success,
    12→    record_email_success, record_first_seen,
    13→};
    14→use email::send_email;
    15→use http::{Comic, XKCD_BASE_URL, download_image, fetch_comic, fetch_comic_by_num};
    16→
    17→const LEGACY_HISTORY_FILE: &str = "xkcd_history.txt";
    18→const COMIC_DIR: &str = "comics";
    19→
    20→fn cmd_version() {
    21→    println!(
    22→        "{} {} ({})",
    23→        env!("CARGO_PKG_NAME"),
    24→        env!("CARGO_PKG_VERSION"),
    25→        env!("GIT_HASH"),
    26→    );
    27→}
    28→
    29→fn main() -> anyhow::Result<()> {
    30→    let _ = dotenvy::dotenv();
    31→    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or("info")).init();
    32→
    33→    if std::env::args().nth(1).as_deref() == Some("version") {
    34→        cmd_version();
    35→        return Ok(());
    36→    }
    37→
    38→    let db_path = std::env::var("XKCD_DB_PATH")
    39→        .map(PathBuf::from)
    40→        .unwrap_or_else(|_| PathBuf::from("xkcd_comics.db"));
    41→    let db = open_db(&db_path)?;
    42→
    43→    migrate_history_file(&db, Path::new(LEGACY_HISTORY_FILE))?;
    44→
    45→    if std::env::args().nth(1).as_deref() == Some("dump") {
    46→        return cmd_dump(&db, &mut std::io::stdout());
    47→    }
    48→
    49→    let config = load_config()?;
    50→
    51→    let agent = ureq::AgentBuilder::new()
    52→        .timeout_connect(Duration::from_secs(30))
    53→        .timeout(Duration::from_secs(60))
    54→        .build();
    55→
    56→    let latest = fetch_comic(&agent, XKCD_BASE_URL)?;
    57→
    58→    // Determine which comic numbers to process this run, oldest first.
    59→    // When there is no history and backfill is enabled, start far enough back so that
    60→    // exactly backfill_limit comics are delivered on the first run.
    61→    let last = last_seen_num(&db)?;
    62→    let start = last.map(|n| n.saturating_add(1)).unwrap_or_else(|| {
    63→        if config.backfill_limit > 0 {
    64→            latest.num.saturating_sub(config.backfill_limit - 1)
    65→        } else {
    66→            latest.num
    67→        }
    68→    });
    69→    let candidates: Vec<u32> = if config.backfill_limit > 0 {
    70→        (start..=latest.num)
    71→            .take(config.backfill_limit as usize)
    72→            .collect()
    73→    } else {
    74→        vec![latest.num]
    75→    };
    76→
    77→    if candidates.is_empty() {
    78→        log::info!("comic #{} already seen, exiting", latest.num);
    79→        return Ok(());
    80→    }
    81→
    82→    for num in candidates {
    83→        let comic = if num == latest.num {
    84→            latest.clone()
    85→        } else {
    86→            match fetch_comic_by_num(&agent, XKCD_BASE_URL, num) {
    87→                Ok(Some(c)) => c,
    88→                Ok(None) => {
    89→                    // Comic intentionally doesn't exist (e.g. #404). Mark seen so we advance past it.
    90→                    log::info!("comic #{num} does not exist, marking as seen");
    91→                    record_first_seen(
    92→                        &db,
    93→                        &Comic {
    94→                            num,
    95→                            safe_title: String::new(),
    96→                            img: String::new(),
    97→                            alt: String::new(),
    98→                            year: String::new(),
    99→                            month: String::new(),
   100→                            day: String::new(),
   101→                        },
   102→                    )?;
   103→                    continue;
   104→                }
   105→                Err(e) => {
   106→                    log::warn!("skipping comic #{num}: {e:#}");
   107→                    continue;
   108→                }
   109→            }
   110→        };
   111→
   112→        if is_seen(&db, &comic)? {
   113→            log::info!("comic #{} already seen, skipping", comic.num);
   114→            continue;
   115→        }
   116→
   117→        // Mark seen immediately — prevents duplicate emails if a later step fails and cron retries.
   118→        record_first_seen(&db, &comic)?;
   119→
   120→        let image_path = if config.download {
   121→            match download_image(&agent, &comic, Path::new(COMIC_DIR)) {
   122→                Ok(path) => {
   123→                    record_download_success(&db, comic.num)?;
   124→                    Some(path)
   125→                }
   126→                Err(e) => {
   127→                    log::warn!("failed to download comic #{}: {e:#}", comic.num);
   128→                    continue;
   129→                }
   130→            }
   131→        } else {
   132→            None
   133→        };
   134→
   135→        let attachment_path = if config.mail_attachment {
   136→            image_path.as_deref()
   137→        } else {
   138→            None
   139→        };
   140→
   141→        if let Err(e) = send_email(&config, &comic, attachment_path) {
   142→            log::warn!("failed to email comic #{}: {e:#}", comic.num);
   143→            continue;
   144→        }
   145→        record_email_success(&db, comic.num)?;
   146→    }
   147→
   148→    Ok(())
   149→}
   150→
   151→#[cfg(test)]
   152→mod tests {
   153→    use super::*;
   154→    use db::{COMICS_TABLE, ComicRecord};
   155→    use http::make_comic;
   156→
   157→    /// Helper: compute backfill candidates using the same logic as main()
   158→    fn backfill_candidates(last: Option<u32>, latest: u32, limit: u32) -> Vec<u32> {
   159→        let start = last.map(|n| n.saturating_add(1)).unwrap_or_else(|| {
   160→            if limit > 0 {
   161→                latest.saturating_sub(limit - 1)
   162→            } else {
   163→                latest
   164→            }
   165→        });
   166→        if limit > 0 {
   167→            (start..=latest).take(limit as usize).collect()
   168→        } else {
   169→            vec![latest]
   170→        }
   171→    }
   172→
   173→    // ── backfill candidate logic ──────────────────────────────────────────────
   174→
   175→    #[test]
   176→    fn backfill_candidates_empty_db() {
   177→        // No prior history + backfill enabled → deliver limit comics ending at latest
   178→        assert_eq!(backfill_candidates(None, 100, 5), vec![96, 97, 98, 99, 100]);
   179→    }
   180→
   181→    #[test]
   182→    fn backfill_candidates_empty_db_limit_one() {
   183→        // limit=1 must not underflow (100 - (1-1) = 100)
   184→        assert_eq!(backfill_candidates(None, 100, 1), vec![100]);
   185→    }
   186→
   187→    #[test]
   188→    fn backfill_candidates_up_to_date() {
   189→        // Already seen the latest — empty list
   190→        assert_eq!(backfill_candidates(Some(100), 100, 5), Vec::<u32>::new());
   191→    }
   192→
   193→    #[test]
   194→    fn backfill_candidates_with_gap() {
   195→        assert_eq!(backfill_candidates(Some(98), 101, 5), vec![99, 100, 101]);
   196→    }
   197→
   198→    #[test]
   199→    fn backfill_candidates_capped() {
   200→        // Gap of 11 but limit=3 → only first 3
   201→        assert_eq!(backfill_candidates(Some(90), 101, 3), vec![91, 92, 93]);
   202→    }
   203→
   204→    #[test]
   205→    fn backfill_candidates_limit_zero() {
   206→        // limit=0 disables backfill — only latest
   207→        assert_eq!(backfill_candidates(Some(98), 101, 0), vec![101]);
   208→    }
   209→
   210→    // ── backfill 404 marked seen ──────────────────────────────────────────────
   211→
   212→    #[test]
   213→    fn backfill_404_marked_seen() {
   214→        // When fetch_comic_by_num returns Ok(None), the num should be recorded as seen
   215→        // so the next run advances past it. We test this via the DB directly.
   216→        let (_dir, db) = db::make_db();
   217→        let placeholder = make_comic(404);
   218→        record_first_seen(&db, &placeholder).unwrap();
   219→        assert!(is_seen(&db, &placeholder).unwrap());
   220→        // email_sent should be false — a 404 placeholder was never emailed
   221→        let rtx = db.begin_read().unwrap();
   222→        let table = rtx.open_table(COMICS_TABLE).unwrap();
   223→        let json = table.get(404u32).unwrap().unwrap().value().to_owned();
   224→        let rec: ComicRecord = serde_json::from_str(&json).unwrap();
   225→        assert!(!rec.email_sent);
   226→    }
   227→}
